import React from "react";

function formatCoordinate(value) {
  if (typeof value !== "number" || Number.isNaN(value)) {
    return "--";
  }

  return value.toFixed(3);
}

function formatNumber(value, digits = 2) {
  if (typeof value !== "number" || Number.isNaN(value)) {
    return "--";
  }

  return value.toFixed(digits);
}

function StatItem({ label, value }) {
  return (
    <div
      style={{
        padding: "8px 10px",
        borderRadius: "9px",
        backgroundColor: "rgba(30, 41, 59, 0.38)",
        border: "1px solid rgba(148, 163, 184, 0.22)",
      }}
    >
      <span style={{ color: "#94a3b8", marginRight: "6px" }}>{label}</span>
      <strong style={{ color: "#e2e8f0", fontWeight: 600 }}>{value}</strong>
    </div>
  );
}

export default function StatusBar({ position, lastUpdated, loading, error }) {
  return (
    <section
      style={{
        marginTop: "12px",
        border: "1px solid #2b3754",
        borderRadius: "12px",
        padding: "10px",
        backgroundColor: "rgba(9, 14, 29, 0.84)",
        display: "flex",
        flexWrap: "wrap",
        gap: "8px",
        fontSize: "13px",
      }}
    >
      <StatItem label="Lat" value={formatCoordinate(position?.latitude)} />
      <StatItem label="Lon" value={formatCoordinate(position?.longitude)} />
      <StatItem label="Alt" value={`${formatNumber(position?.altitude)} km`} />
      <StatItem label="Vel" value={`${formatNumber(position?.velocity)} km/h`} />
      <StatItem
        label="Updated"
        value={lastUpdated ? lastUpdated.toLocaleTimeString() : loading ? "Loading..." : "--"}
      />
      {error ? (
        <div style={{ color: "#fca5a5", alignSelf: "center", paddingLeft: "4px" }}>
          API Error: {error}
        </div>
      ) : null}
    </section>
  );
}
